function calculateSafetyIndex(inputs) {
  const { 
    forecast_temperature_c, 
    forecast_wind_speed_kmh, 
    forecast_precipitation_mm_hr, 
    terrain_steepness_degrees, 
    terrain_exposure_level, 
    personal_experience_level, 
    gear_readiness_level, 
    group_size, 
    emergency_kit_status, 
    first_aid_cert_present 
  } = inputs;

  let base_score = 50;
  let total_penalty = 0;
  let total_bonus = 0;

  // --- Weather Impacts ---

  // Temperature Penalty (optimal 10-20C)
  let temp_penalty = 0;
  if (forecast_temperature_c < 0) {
    temp_penalty = Math.abs(forecast_temperature_c) * 2.5; // Very cold
  } else if (forecast_temperature_c < 10) {
    temp_penalty = (10 - forecast_temperature_c) * 1;
  } else if (forecast_temperature_c > 20) {
    temp_penalty = (forecast_temperature_c - 20) * 1.5;
  } else if (forecast_temperature_c > 30) {
    temp_penalty = (forecast_temperature_c - 30) * 3; // Very hot
  }
  total_penalty += Math.min(temp_penalty, 30); // Cap temp penalty

  // Wind Speed Penalty
  let wind_penalty = 0;
  if (forecast_wind_speed_kmh > 40) {
    wind_penalty = (forecast_wind_speed_kmh - 40) * 1.5; // High wind
  } else if (forecast_wind_speed_kmh > 20) {
    wind_penalty = (forecast_wind_speed_kmh - 20) * 0.8;
  } else if (forecast_wind_speed_kmh > 10) {
    wind_penalty = (forecast_wind_speed_kmh - 10) * 0.3;
  }
  total_penalty += Math.min(wind_penalty, 25); // Cap wind penalty

  // Precipitation Penalty
  let precip_penalty = 0;
  if (forecast_precipitation_mm_hr > 5) {
    precip_penalty = (forecast_precipitation_mm_hr - 5) * 4;
  } else if (forecast_precipitation_mm_hr > 1) {
    precip_penalty = (forecast_precipitation_mm_hr - 1) * 2;
  }
  total_penalty += Math.min(precip_penalty, 35); // Cap precip penalty

  // --- Terrain Impacts ---

  // Steepness Penalty
  let steepness_penalty = 0;
  if (terrain_steepness_degrees > 35) {
    steepness_penalty = (terrain_steepness_degrees - 35) * 2.5; // Very steep, avalanche terrain
  } else if (terrain_steepness_degrees > 25) {
    steepness_penalty = (terrain_steepness_degrees - 25) * 1.2;
  } else if (terrain_steepness_degrees > 15) {
    steepness_penalty = (terrain_steepness_degrees - 15) * 0.5;
  }
  total_penalty += Math.min(steepness_penalty, 40); // Cap steepness penalty

  // Exposure Level Penalty
  const exposure_penalties = [0, 5, 12, 25, 40]; // Index 0 for 1, 1 for 2 etc.
  total_penalty += exposure_penalties[terrain_exposure_level - 1];

  // --- Personal & Group Factors ---

  // Experience Level Bonus/Penalty
  const experience_bonuses = [-30, -15, 0, 10, 20]; // 1=Novice, 5=Expert
  total_bonus += experience_bonuses[personal_experience_level - 1];

  // Gear Readiness Bonus/Penalty
  const gear_bonuses = [-25, -10, 0, 10, 20]; // 1=Inadequate, 5=Fully Prepared
  total_bonus += gear_bonuses[gear_readiness_level - 1];

  // Group Size Bonus/Penalty
  let group_bonus = 0;
  if (group_size === 1) {
    group_bonus = -20;
  } else if (group_size === 2) {
    group_bonus = -10;
  } else if (group_size >= 3 && group_size <= 5) {
    group_bonus = 10; // Optimal group size for safety and efficiency
  } else if (group_size > 5) {
    group_bonus = 0; // Larger groups can have logistical challenges despite more hands
  }
  total_bonus += group_bonus;

  // Emergency Kit Status Bonus/Penalty
  const emergency_kit_bonuses = [-15, -5, 0, 5, 15];
  total_bonus += emergency_kit_bonuses[emergency_kit_status - 1];

  // First Aid Certification Bonus/Penalty
  total_bonus += (first_aid_cert_present === 1) ? 10 : -10;

  // --- Final Calculation ---
  let safety_index = base_score - total_penalty + total_bonus;

  // Cap index between 0 and 100
  safety_index = Math.max(0, Math.min(100, safety_index));

  // Determine Risk Category
  let risk_category;
  if (safety_index >= 80) {
    risk_category = "Low Risk";
  } else if (safety_index >= 60) {
    risk_category = "Moderate Risk";
  } else if (safety_index >= 40) {
    risk_category = "Elevated Risk";
  } else if (safety_index >= 20) {
    risk_category = "High Risk";
  } else {
    risk_category = "Extreme Risk";
  }

  return {
    safety_index: Math.round(safety_index),
    risk_category: risk_category
  };
}
